      id,
      title: '',
      poster: '',
      year: '',
      desc: '',
      playbacks: [{
        sourceId,
        sourceName: '播放源',
        episodes: [],
        episodes_titles: []
      }]
    };
  },

  async resolvePlayUrl(ctx, { playUrl, sourceId, episodeIndex }) {
    return { url: playUrl, type: 'auto', headers: {} };
  }
};

