return {
  meta: { name: 'fanmingming/live ★28.1k', author: 'MoonTVPlus' },

  _channels: null,

  async init(ctx) {
    if (this._channels) return;
    const urls = [
      'https://raw.githubusercontent.com/fanmingming/live/main/tv/m3u/ipv6.m3u',
      'https://raw.githubusercontent.com/fanmingming/live/main/tv/m3u/tv.m3u'
    ];
    this._channels = [];
    for (const url of urls) {
      try {
        const text = await ctx.request.get(url);
        const lines = text.split('\n');
        for (let i = 0; i < lines.length; i++) {
          if (lines[i].startsWith('#EXTINF:')) {
            const name = lines[i].split(',')[1]?.trim() || '未知';
            const url2 = lines[i + 1]?.trim();
            if (url2 && url2.startsWith('http')) {
              this._channels.push({ id: String(this._channels.length), name, url: url2 });
            }
          }
        }
      } catch (e) {
        ctx.log.warn('加载直播源失败: ' + url);
      }
    }
  },

  async getSources(ctx) {
    await this.init(ctx);
    return [{ id: 'all', name: '全部频道 (' + this._channels.length + '个)' }];
  },

  async search(ctx, { keyword, page }) {
    await this.init(ctx);
    const filtered = this._channels.filter(c => c.name.includes(keyword));
    const pageSize = 30;
    const start = (page - 1) * pageSize;
    const items = filtered.slice(start, start + pageSize);
    return {
      list: items.map(c => ({
        id: c.id,
        title: c.name,
        poster: '',
        year: '',
        desc: c.url,
        type_name: '直播'
      })),
      page,
      pageCount: Math.ceil(filtered.length / pageSize),
      total: filtered.length
    };
  },

  async recommend(ctx, { page }) {
    return this.search(ctx, { keyword: '', page: page || 1 });
  },

  async detail(ctx, { id, sourceId }) {
    await this.init(ctx);
    const channel = this._channels.find(c => c.id === id);
    return {
      id,
      title: channel?.name || '',
      poster: '',
      year: '',
      desc: '',
      playbacks: channel ? [{
        sourceId,
        sourceName: '直播',
        episodes: [{ playUrl: channel.url, needResolve: false }],
        episodes_titles: [channel.name]
      }] : []
    };
  },

  async resolvePlayUrl(ctx, { playUrl }) {
    return { url: playUrl, type: 'm3u8', headers: {} };
  }
};

